-- Word Sky starter words: JLPT N5 and N4
-- Source: Tanos JLPT vocabulary PDFs.
-- These starter words are for Word Sky only. They are not book encounters.

create table if not exists public.word_sky_starter_words (
  id uuid primary key default gen_random_uuid(),
  surface text not null,
  reading text not null,
  meaning text not null,
  jlpt_level text not null check (jlpt_level in ('N5', 'N4', 'N3', 'N2', 'N1', 'NON-JLPT')),
  source text not null default 'manual',
  source_url text,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (surface, reading, meaning, jlpt_level, source)
);

alter table public.word_sky_starter_words enable row level security;

drop policy if exists "word_sky_starter_words_select_authenticated" on public.word_sky_starter_words;
create policy "word_sky_starter_words_select_authenticated"
on public.word_sky_starter_words
for select
to authenticated
using (active = true);

create index if not exists word_sky_starter_words_active_level_idx
on public.word_sky_starter_words (active, jlpt_level);

